local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxGuildCtrl:LxBaseCtrl
local LxGuildCtrl = classX("LxGuildCtrl", LxBaseCtrl)

function LxGuildCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
end

function LxGuildCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

-- 打开军团界面
function LxGuildCtrl:OpenGuild()
    if not CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.Guild, FuncOpenTipsEnum.Normal) then
        return
    end

    if self:HadGuild() then
        -- ShowPanel(UiNames.Guild)
        ShowPanel(UiNames.GuildHome)
        return
    end
    local isFirstJoin = ModuleCenter.Guild:GetNeverJoinGuildState()
    if isFirstJoin then
        ShowPanel(UiNames.GuildFirstCreate)
    else
        HandlerCenter.Guild:ListGuildReq("")
        ShowPanel(UiNames.GuildApplyList)
    end
    
end

-- 打开军团捐献界面
function LxGuildCtrl:OpenGuildDonate()
    if not CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.Guild, FuncOpenTipsEnum.Normal) then
        return
    end

    if self:HadGuild() then
        -- ShowPanel(UiNames.Guild)
        -- ShowPanel(UiNames.GuildDonate)
        ShowPanel(UiNames.GuildHome)
        return
    end
    ShowSysMsg(I18nText(5581))
end

