-- true 表示已加入军团
function LxGuildCtrl:HadGuild(id)
    if not id then
        local info = ModuleCenter.Guild:GetGuildInfo()
        id = info.id
    end
    id = checknumber(id)
    return id ~= 0
end

-- 获取玩家申请列表红点
function LxGuildCtrl:GetPlayerApplyRedNum()
    -- local ctrl = MgrCenter.PanelMgr:GetPanelCtrl(UiNames.GuildPlayerApplyList)
    -- if ctrl then
    --     return 0
    -- end

    -- local myJobId = ModuleCenter.Guild:GetMyJobId()
    -- if myJobId == GuildJob.Member then
    --     return 0
    -- end
    if not self:CheckSelfIsLeader() then
        return 0
    end
    local curTime = ModuleCenter.Guild:GetLookAtGuildPlayerApplyTime()
    local num = 0
    for _, time in pairs(ModuleCenter.Guild:GetGuildPlayerApplyMap()) do
        if curTime < time then
            num = num + 1
        end
    end
    return num
end

-- 获取玩家捐献红点
function LxGuildCtrl:GetDonateRedNum()
    if not CtrlCenter.FuncOpen:IsFuncOpen(FuncOpnIdConst.GuildDonate, FuncOpenTipsEnum.None) then
        return 0
    end

    local ctrl = MgrCenter.PanelMgr:GetPanelCtrl(UiNames.GuildDonate)
    if ctrl then
        return 0
    end

    local myJobId = ModuleCenter.Guild:GetMyJobId()
    if myJobId == GuildJob.Member then
        return 0
    end

    local costList = ModuleCenter.Guild:GetDonateCostAndAward()
    if costList then
        return 0
    end
    return 1
end

-- 获取军团红点总数
function LxGuildCtrl:GetRedNum()
    if not CtrlCenter.FuncOpen:IsFuncOpen(FuncOpnIdConst.Guild, FuncOpenTipsEnum.None) then
        return 0
    end

    if not self:HadGuild() then
        return 0
    end

    local num = self:GetPlayerApplyRedNum()
    num = num + self:GetDonateRedNum()
    return num
end


--特殊官职的成员信息
function LxGuildCtrl:GetOfficialMember(guildJob)
    local memberList = {}
    local info = ModuleCenter.Guild:GetGuildInfo()
    if info then
        memberList = info.members or {}
        for key,member in pairs(memberList) do
            if member.guildJob == guildJob then
                return member
            end
        end
    end
    return false
end


function LxGuildCtrl:CheckIsLeader(roleId)
    local info = ModuleCenter.Guild:GetGuildInfo()
    if info and info.chairman and info.chairman.roleId == roleId then
        return true
    end
    return false
end

function LxGuildCtrl:CheckSelfIsLeader()
    return self:CheckIsLeader(ModuleCenter.Role:GetRoleInfo().roleId)
end

function LxGuildCtrl:CheckRoleIsSelf(roleId)
    return ModuleCenter.Login:IsSelf(roleId)
end

function LxGuildCtrl:GetGuildMemberList() --不包括盟主
    local guildInfo = ModuleCenter.Guild:GetGuildInfo()
    if not guildInfo then
        return {}
    end
    local memberList = guildInfo.members or {}
    local members = {}
    for i = 1,#memberList do
        if not self:CheckIsLeader(memberList[i].roleInfo.roleId) then
            table.insert(members,memberList[i])
        end
    end
    return members
end

-- 得到成员阶位
function LxGuildCtrl:GetGuildMemberRank(roleId)
    if not roleId then
        roleId = ModuleCenter.Role:GetRoleInfo().roleId
    end
    local guildInfo = ModuleCenter.Guild:GetGuildInfo()
    if guildInfo then
        local memberList = guildInfo.members or {}
        for i = 1,#memberList do
            if memberList[i].roleInfo.roleId == roleId then
                return memberList[i].guildRank
            end
        end
    end
    return 2
end

-- 得到成员职位
function LxGuildCtrl:GetGuildMemberJob(roleId)
    if not roleId then
        roleId = ModuleCenter.Role:GetRoleInfo().roleId
    end
    local guildInfo = ModuleCenter.Guild:GetGuildInfo()
    if guildInfo then
        local memberList = guildInfo.members or {}
        for i = 1,#memberList do
            if memberList[i].roleInfo.roleId == roleId then
                return memberList[i].guildJob
            end
        end
    end
    return 5
end

--同盟帮助红点
function LxGuildCtrl:GetGuildHelpRedNum()
    if not self:HadGuild() then
        return 0
    end
    local helpList = ModuleCenter.Guild:GetGuildHelpList()
    local helpNum = 0
    for i = 1,#helpList do
        local roleInfo = helpList[i].roleInfo
        if not self:CheckRoleIsSelf(roleInfo.roleId) then
            helpNum = helpNum + 1
        end
    end
    return helpNum,true
end

--同盟红点
function LxGuildCtrl:GetGuildRedNum()
    local sumNum = 0
    sumNum = sumNum + self:GetGuildHelpRedNum()
    sumNum = sumNum + self:GetPlayerApplyRedNum()
    sumNum = sumNum + self:GetGuildRankApplicationRedNum()
    if ModuleCenter.GuildScience:GetIsShowScienceRed() then
        sumNum = sumNum + 1
    end

    if sumNum > 0 then
        return sumNum,true
    end

    return 0,false
end

--同盟管理红点
function LxGuildCtrl:GetGuildManagerRed()
    local num = self:GetPlayerApplyRedNum()
    if num > 0 then
        return true
    end
    return false
end

--同盟申请阶位红点
function LxGuildCtrl:GetGuildRankApplicationRedNum()
    if self:CheckSelfIsLeader() then
        local list = ModuleCenter.Guild:GetGuildUpgradeRequestList()
        if #list > 0 then
            return 1
        end
    end
    return 0
end

--同盟公民红点
function LxGuildCtrl:GetGuildMemberRed()
    local num = self:GetGuildRankApplicationRedNum()
    if num > 0 then
        return num,false
    end
    return 0,false
end

function LxGuildCtrl:GetSelfPermissions()
    local guildRank = self:GetGuildMemberRank()
    local guildJob = self:GetGuildMemberJob()
    local classRef = GameTable.GuildClassRef[guildRank]
    local postRef = GameTable.GuildPostRef[guildJob]
    local permissions = {}
    if classRef then
        local powers = classRef.power or {}
        for i = 1, #powers do
            permissions[powers[i]] = true
        end
    end

    if postRef then
        local powers = postRef.power or {}
        for i = 1, #powers do
            permissions[powers[i]] = true
        end
    end
    return permissions
end

