function LxGuildCtrl:GetSelfHelpBuildInfo(buildId,type)
    local helpList = ModuleCenter.Guild:GetGuildHelpList()
    for _, v in ipairs(helpList) do
        if v.type == type then
            local roleInfo = v.roleInfo
            local isSelf = self:CheckRoleIsSelf(roleInfo.roleId)
            if isSelf then
                local moreInfo = v.moreInfo
                local helpStr = string.split(moreInfo, "_")
                local info1 = checknumber(helpStr[1])
                if info1 == buildId then
                    return v
                end
            end
        end
    end
    return nil
end

function LxGuildCtrl:ReqGuildHelpList()
    local hasGuild = self:HadGuild()
    if hasGuild then
        HandlerCenter.Guild:GuildHelpListReq()
    end
end

--权限是否可设置
function LxGuildCtrl:CheckPermissionSetting(perId,perList)
    if perList then
        for i = 1, #perList do
            if perList[i] == perId then
                return true
            end
        end
    end
    return false
end

--阶位开关
function LxGuildCtrl:CheckRankOpenState(refId)
    local rankConditions = ModuleCenter.Guild:GetGuildRankConditions()
    for k, v in ipairs(rankConditions) do
        if refId == v.guildRank then
            return v.autoRank
        end
    end
    return false
end

--阶位名字
function LxGuildCtrl:CheckRankName(refId)
    local rankConditions = ModuleCenter.Guild:GetGuildRankConditions()
    for k, v in ipairs(rankConditions) do
        if refId == v.guildRank then
            if v.nickname and v.nickname ~= "" then
                return v.nickname
            end
        end
    end
    return ""
end

return LxGuildCtrl
